SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS=0;

DROP TABLE IF EXISTS `migrations`;
CREATE TABLE `migrations` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `migration` VARCHAR(255) not null, `batch` integer not null) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` VARCHAR(255) not null, `email` VARCHAR(255) not null, `email_verified_at` datetime, `password` VARCHAR(255) not null, `remember_token` VARCHAR(255), `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `password_reset_tokens`;
CREATE TABLE `password_reset_tokens` (`email` VARCHAR(255) not null, `token` VARCHAR(255) not null, `created_at` datetime, primary key (`email`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `sessions`;
CREATE TABLE `sessions` (`id` VARCHAR(255) not null, `user_id` integer, `ip_address` VARCHAR(255), `user_agent` text, `payload` text not null, `last_activity` integer not null, primary key (`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `cache`;
CREATE TABLE `cache` (`key` VARCHAR(255) not null, `value` text not null, `expiration` integer not null, primary key (`key`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `cache_locks`;
CREATE TABLE `cache_locks` (`key` VARCHAR(255) not null, `owner` VARCHAR(255) not null, `expiration` integer not null, primary key (`key`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `jobs`;
CREATE TABLE `jobs` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `queue` VARCHAR(255) not null, `payload` text not null, `attempts` integer not null, `reserved_at` integer, `available_at` integer not null, `created_at` integer not null) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `job_batches`;
CREATE TABLE `job_batches` (`id` VARCHAR(255) not null, `name` VARCHAR(255) not null, `total_jobs` integer not null, `pending_jobs` integer not null, `failed_jobs` integer not null, `failed_job_ids` text not null, `options` text, `cancelled_at` integer, `created_at` integer not null, `finished_at` integer, primary key (`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `failed_jobs`;
CREATE TABLE `failed_jobs` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `uuid` VARCHAR(255) not null, `connection` text not null, `queue` text not null, `payload` text not null, `exception` text not null, `failed_at` datetime not null default CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `settings`;
CREATE TABLE `settings` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `group` VARCHAR(255) not null, `name` VARCHAR(255) not null, `locked` TINYINT(1) NOT NULL DEFAULT 0, `payload` text not null, `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `pages`;
CREATE TABLE `pages` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `title` text not null, `slug` VARCHAR(255) not null, `meta_title` text, `meta_description` text, `og_title` text, `og_description` text, `og_image` VARCHAR(255), `blocks` text, `schema_org` text, `status` VARCHAR(255) check (`status` in ('draft', 'published', 'archived')) not null default 'draft', `is_home` TINYINT(1) NOT NULL DEFAULT 0, `sort_order` integer not null default '0', `parent_id` integer, `created_at` datetime, `updated_at` datetime, `deleted_at` datetime, foreign key(`parent_id`) references `pages`(`id`) on delete set null) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `menus`;
CREATE TABLE `menus` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `location` VARCHAR(255) not null, `label` text not null, `items` text, `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `layouts`;
CREATE TABLE `layouts` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `type` VARCHAR(255) check (`type` in ('header', 'footer')) not null, `rows` text, `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `form_submissions`;
CREATE TABLE `form_submissions` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `form_key` VARCHAR(255) not null, `data` text not null, `ip_address` VARCHAR(255), `user_agent` VARCHAR(255), `read_at` datetime, `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `qr_menu_restaurants`;
CREATE TABLE `qr_menu_restaurants` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` text not null, `description` text, `slug` VARCHAR(255) not null, `logo` VARCHAR(255), `working_hours` text, `currency` VARCHAR(255) not null default 'TRY', `primary_color` VARCHAR(255) not null default '#1a1a2e', `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `qr_menu_tables`;
CREATE TABLE `qr_menu_tables` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `restaurant_id` integer not null, `name` VARCHAR(255) not null, `qr_code_url` VARCHAR(255), `qr_code_path` VARCHAR(255), `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime, foreign key(`restaurant_id`) references `qr_menu_restaurants`(`id`) on delete cascade) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `qr_menu_categories`;
CREATE TABLE `qr_menu_categories` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `restaurant_id` integer not null, `name` text not null, `description` text, `image` VARCHAR(255), `sort_order` integer not null default '0', `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime, foreign key(`restaurant_id`) references `qr_menu_restaurants`(`id`) on delete cascade) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `qr_menu_items`;
CREATE TABLE `qr_menu_items` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `category_id` integer not null, `restaurant_id` integer not null, `name` text not null, `description` text, `price` numeric not null default '0', `image` VARCHAR(255), `allergens` text, `badges` text, `is_featured` TINYINT(1) NOT NULL DEFAULT 0, `is_available` tinyint(1) not null default '1', `sort_order` integer not null default '0', `created_at` datetime, `updated_at` datetime, foreign key(`category_id`) references `qr_menu_categories`(`id`) on delete cascade, foreign key(`restaurant_id`) references `qr_menu_restaurants`(`id`) on delete cascade) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `blog_categories`;
CREATE TABLE `blog_categories` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` text not null, `slug` VARCHAR(255) not null, `description` text, `color` VARCHAR(255), `sort_order` integer not null default '0', `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `blog_posts`;
CREATE TABLE `blog_posts` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `author_id` integer, `category_id` integer, `title` text not null, `slug` VARCHAR(255) not null, `excerpt` text, `content` text, `meta_title` text, `meta_description` text, `featured_image` VARCHAR(255), `status` VARCHAR(255) check (`status` in ('draft', 'published', 'scheduled', 'archived')) not null default 'draft', `published_at` datetime, `is_featured` TINYINT(1) NOT NULL DEFAULT 0, `read_time` integer, `view_count` integer not null default '0', `created_at` datetime, `updated_at` datetime, `deleted_at` datetime, foreign key(`author_id`) references `users`(`id`) on delete set null, foreign key(`category_id`) references `blog_categories`(`id`) on delete set null) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `blog_post_tags`;
CREATE TABLE `blog_post_tags` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` text not null, `slug` VARCHAR(255) not null, `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `blog_post_tag`;
CREATE TABLE `blog_post_tag` (`post_id` integer not null, `tag_id` integer not null, foreign key(`post_id`) references `blog_posts`(`id`) on delete cascade, foreign key(`tag_id`) references `blog_post_tags`(`id`) on delete cascade, primary key (`post_id`, `tag_id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `services`;
CREATE TABLE `services` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `title` text not null, `slug` VARCHAR(255) not null, `short_description` text, `description` text, `icon` VARCHAR(255), `featured_image` VARCHAR(255), `meta_title` text, `meta_description` text, `features` text, `price_from` numeric, `status` VARCHAR(255) check (`status` in ('draft', 'published')) not null default 'draft', `is_featured` TINYINT(1) NOT NULL DEFAULT 0, `sort_order` integer not null default '0', `created_at` datetime, `updated_at` datetime, `deleted_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `portfolio_categories`;
CREATE TABLE `portfolio_categories` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` text not null, `slug` VARCHAR(255) not null, `sort_order` integer not null default '0', `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `portfolio_projects`;
CREATE TABLE `portfolio_projects` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `category_id` integer, `title` text not null, `slug` VARCHAR(255) not null, `short_description` text, `description` text, `client_name` text, `client_url` VARCHAR(255), `completed_at` date, `technologies` text, `meta_title` text, `meta_description` text, `status` VARCHAR(255) check (`status` in ('draft', 'published')) not null default 'draft', `is_featured` TINYINT(1) NOT NULL DEFAULT 0, `sort_order` integer not null default '0', `created_at` datetime, `updated_at` datetime, `deleted_at` datetime, foreign key(`category_id`) references `portfolio_categories`(`id`) on delete set null) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `team_members`;
CREATE TABLE `team_members` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` text not null, `slug` VARCHAR(255) not null, `position` text not null, `bio` text, `email` VARCHAR(255), `phone` VARCHAR(255), `social_links` text, `photo` VARCHAR(255), `is_active` tinyint(1) not null default '1', `sort_order` integer not null default '0', `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `contact_submissions`;
CREATE TABLE `contact_submissions` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` VARCHAR(255) not null, `email` VARCHAR(255) not null, `phone` VARCHAR(255), `subject` VARCHAR(255), `message` text not null, `form_key` VARCHAR(255) not null default 'contact', `ip_address` VARCHAR(255), `status` VARCHAR(255) not null default 'new', `read_at` datetime, `replied_at` datetime, `admin_notes` text, `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `meeting_staff`;
CREATE TABLE `meeting_staff` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` VARCHAR(255) not null, `email` VARCHAR(255) not null, `phone` VARCHAR(255), `photo` VARCHAR(255), `title` text, `bio` text, `expertise` text, `working_hours` text, `meeting_duration` integer not null default '30', `buffer_time` integer not null default '15', `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime, `team_member_id` integer) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `meeting_appointments`;
CREATE TABLE `meeting_appointments` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `staff_id` integer not null, `client_name` VARCHAR(255) not null, `client_email` VARCHAR(255) not null, `client_phone` VARCHAR(255), `notes` text, `starts_at` datetime not null, `ends_at` datetime not null, `timezone` VARCHAR(255) not null default 'Europe/Istanbul', `status` VARCHAR(255) check (`status` in ('pending', 'confirmed', 'cancelled', 'completed')) not null default 'pending', `meeting_type` VARCHAR(255) check (`meeting_type` in ('zoom', 'google_meet', 'teams', 'phone', 'in_person')) not null default 'zoom', `meeting_link` VARCHAR(255), `meeting_id` VARCHAR(255), `meeting_password` VARCHAR(255), `reminder_sent_at` datetime, `cancellation_reason` VARCHAR(255), `created_at` datetime, `updated_at` datetime, foreign key(`staff_id`) references `meeting_staff`(`id`) on delete cascade) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `meeting_blocked_slots`;
CREATE TABLE `meeting_blocked_slots` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `staff_id` integer, `starts_at` datetime not null, `ends_at` datetime not null, `reason` VARCHAR(255), `is_recurring` TINYINT(1) NOT NULL DEFAULT 0, `created_at` datetime, `updated_at` datetime, foreign key(`staff_id`) references `meeting_staff`(`id`) on delete cascade) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `media`;
CREATE TABLE `media` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `model_type` VARCHAR(255) not null, `model_id` integer not null, `uuid` VARCHAR(255), `collection_name` VARCHAR(255) not null, `name` VARCHAR(255) not null, `file_name` VARCHAR(255) not null, `mime_type` VARCHAR(255), `disk` VARCHAR(255) not null, `conversions_disk` VARCHAR(255), `size` integer not null, `manipulations` text not null, `custom_properties` text not null, `generated_conversions` text not null, `responsive_images` text not null, `order_column` integer, `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `permissions`;
CREATE TABLE `permissions` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` VARCHAR(255) not null, `guard_name` VARCHAR(255) not null, `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `roles`;
CREATE TABLE `roles` (`id` INT NOT NULL AUTO_INCREMENT PRIMARY KEY, `name` VARCHAR(255) not null, `guard_name` VARCHAR(255) not null, `created_at` datetime, `updated_at` datetime) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `model_has_permissions`;
CREATE TABLE `model_has_permissions` (`permission_id` integer not null, `model_type` VARCHAR(255) not null, `model_id` integer not null, foreign key(`permission_id`) references `permissions`(`id`) on delete cascade, primary key (`permission_id`, `model_id`, `model_type`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `model_has_roles`;
CREATE TABLE `model_has_roles` (`role_id` integer not null, `model_type` VARCHAR(255) not null, `model_id` integer not null, foreign key(`role_id`) references `roles`(`id`) on delete cascade, primary key (`role_id`, `model_id`, `model_type`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `role_has_permissions`;
CREATE TABLE `role_has_permissions` (`permission_id` integer not null, `role_id` integer not null, foreign key(`permission_id`) references `permissions`(`id`) on delete cascade, foreign key(`role_id`) references `roles`(`id`) on delete cascade, primary key (`permission_id`, `role_id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


SET FOREIGN_KEY_CHECKS=1;
