INSERT INTO `pages` (`id`, `title`, `slug`, `meta_title`, `meta_description`, `og_title`, `og_description`, `og_image`, `blocks`, `schema_org`, `status`, `is_home`, `sort_order`, `parent_id`, `created_at`, `updated_at`, `deleted_at`) VALUES ('1', '{"tr":"Ana Sayfa","en":"Home"}', 'home', '{"tr":"Special Roma — Mordoğan Cafe & Dondurma","en":"Special Roma"}', '{"tr":"1995’ten beri Mordoğan’da dondurma, kahvaltı ve tatlı. Cumhuriyet Meydanı deniz kenarı.","en":"Gelato & breakfast in Mordoğan since 1995."}', '{"tr":null}', '{"tr":null}', NULL, '[{"type":"roma_hero","data":{"heading":"1995\u2019ten beri Mordo\u011fan\u2019\u0131n efsane lezzetleri","subheading":"Deniz kenar\u0131nda premium ama samimi bir mola: Roma dondurmalar\u0131, serpme kahvalt\u0131 ve tatl\u0131 bar.","button_label":"Men\u00fcy\u00fc \u0130ncele","button_url":"http:\/\/specialroma.test\/menu\/special-roma\/4","button2_label":"Lokasyon","button2_url":"\/iletisim","background_image":null}},{"type":"services_grid","data":{"heading":"Cafe\u2019mizin Y\u0131ld\u0131zlar\u0131: Favoriler","columns":"3","services":[{"title":"Roma Dondurmalar\u0131","description":"Klasik ve special aromalar \u2014 her g\u00fcn taze.","icon":"\ud83c\udf68","url":"http:\/\/specialroma.test\/menu\/special-roma\/4"},{"title":"Serpme Kahvalt\u0131","description":"Zengin peynir & zeytin se\u00e7kisi, deniz manzaras\u0131.","icon":"\ud83c\udf73","url":"http:\/\/specialroma.test\/menu\/special-roma\/4"},{"title":"Patisserie","description":"Dilim pasta, waffle ve \u015ferbetli tatl\u0131lar.","icon":"\ud83c\udf70","url":"http:\/\/specialroma.test\/menu\/special-roma\/4"}]}},{"type":"roma_dondurmalar","data":{"heading":"Roma Dondurmalar\u0131","text":"Onlarca aromayla haz\u0131rlanan geleneksel Roma tarz\u0131 dondurma \u2014 hem klasik hem special \u00e7e\u015fitler.","button_label":"T\u00fcm men\u00fcy\u00fc g\u00f6r","button_url":"http:\/\/specialroma.test\/menu\/special-roma\/4"}},{"type":"services_grid","data":{"heading":"En pop\u00fcler lezzetler","columns":"3","services":[{"title":"Serpme Kahvalt\u0131","description":"Payla\u015f\u0131ml\u0131 zengin kahvalt\u0131 sofras\u0131.","icon":"\ud83e\udd50","url":"http:\/\/specialroma.test\/menu\/special-roma\/4"},{"title":"Roma Burger","description":"\u00d6zel sos ve kaliteli et.","icon":"\ud83c\udf54","url":"http:\/\/specialroma.test\/menu\/special-roma\/4"},{"title":"Fragola Sogna","description":"Meyve ve dondurma uyumu.","icon":"\ud83c\udf53","url":"http:\/\/specialroma.test\/menu\/special-roma\/4"},{"title":"Penne Mexicana","description":"Baharatl\u0131 ve doyurucu.","icon":"\ud83c\udf5d","url":"http:\/\/specialroma.test\/menu\/special-roma\/4"},{"title":"Roma Waffle","description":"\u00c7\u0131t\u0131r waffle, se\u00e7ti\u011finiz malzemeler.","icon":"\ud83e\uddc7","url":"http:\/\/specialroma.test\/menu\/special-roma\/4"},{"title":"Karamel Frappe","description":"Serinleten so\u011fuk kahve.","icon":"\u2615","url":"http:\/\/specialroma.test\/menu\/special-roma\/4"}]}},{"type":"text","data":{"alignment":"center","content":"<h2>Hikayemiz<\/h2><p class=\"sr-story-lead\">1995\u2019ten bu yana, Mordo\u011fan Cumhuriyet Meydan\u0131\u2019nda denizin hemen kenar\u0131nda misafirlerimize lezzet ve huzur sunuyoruz.<\/p><div class=\"sr-story-timeline\"><div class=\"sr-story-year\"><span class=\"sr-story-year__badge\">1995<\/span><p>Mordo\u011fan meydan\u0131nda k\u00fc\u00e7\u00fck bir dondurma d\u00fckk\u00e2n\u0131 olarak kap\u0131lar\u0131m\u0131z\u0131 a\u00e7t\u0131k. \u0130lk y\u0131ldan Ege\u2019nin en sevilen dura\u011f\u0131 olmay\u0131 ba\u015fard\u0131k.<\/p><\/div><div class=\"sr-story-year\"><span class=\"sr-story-year__badge\">2005<\/span><p>Kahvalt\u0131 ve tatl\u0131 bar men\u00fcm\u00fcz\u00fc geni\u015flettik. Serpme kahvalt\u0131m\u0131z Mordo\u011fan\u2019\u0131n simgesi haline geldi.<\/p><\/div><div class=\"sr-story-year\"><span class=\"sr-story-year__badge\">2015<\/span><p>Mekan\u0131m\u0131z\u0131 yeniledik, modern bir tasar\u0131mla deniz manzaras\u0131n\u0131 sofraya ta\u015f\u0131d\u0131k.<\/p><\/div><div class=\"sr-story-year\"><span class=\"sr-story-year__badge\">Bug\u00fcn<\/span><p>30 y\u0131l\u0131 a\u015fk\u0131n tecr\u00fcbe, ayn\u0131 tutku. Onlarca dondurma aromas\u0131, geni\u015f men\u00fc ve samimi bir hizmet anlay\u0131\u015f\u0131yla buraday\u0131z.<\/p><\/div><\/div>"}},{"type":"testimonials","data":{"heading":"Misafirlerimiz ne diyor?","eyebrow":"Yorumlar","items":[{"quote":"Dondurmalar harika, manzara e\u015fsiz. Her yaz mutlaka u\u011fruyoruz.","author_name":"Elif S.","author_title":"\u0130zmir","author_photo":null},{"quote":"Serpme kahvalt\u0131 ger\u00e7ekten doyurucu ve taze. Personel \u00e7ok ilgili.","author_name":"Can T.","author_title":"Mordo\u011fan","author_photo":null},{"quote":"Roma waffle ve special dondurma se\u00e7imi ile \u00e7ocuklar bay\u0131ld\u0131.","author_name":"P\u0131nar K.","author_title":"Ala\u00e7at\u0131","author_photo":null}]}},{"type":"text","data":{"alignment":"center","content":"<h2>Konum<\/h2><p><strong>Adres:<\/strong> Cumhuriyet Meydan\u0131 No:13, Mordo\u011fan \u2014 deniz kenar\u0131<\/p><div style=\"margin: 2rem 0; border-radius: 1.5rem; overflow: hidden; border: 1px solid rgb(196 54 110 \/ 0.1); box-shadow: 0 10px 30px -10px rgba(0,0,0,0.1);\"><iframe src=\"https:\/\/www.google.com\/maps\/embed?pb=!1m18!1m12!1m3!1d780.4180906623133!2d26.625279969662788!3d38.51826659823799!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x14bbbba1501077af%3A0x599969cc9c850e5f!2sSpecial%20Roma%20cafe%20%26%20Patisseria!5e0!3m2!1str!2sus!4v1775059217298!5m2!1str!2sus\" width=\"100%\" height=\"450\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"no-referrer-when-downgrade\"><\/iframe><\/div><p><a class=\"btn-primary\" style=\"display:inline-flex;margin-top:0.5rem;\" href=\"\/iletisim\">Yol tarifi & ileti\u015fim<\/a><\/p>"}},{"type":"cta_banner","data":{"heading":"Bug\u00fcn Mordo\u011fan\u2019da m\u0131s\u0131n\u0131z?","subheading":"Rezervasyon ve sorular\u0131n\u0131z i\u00e7in aray\u0131n veya WhatsApp\u2019tan yaz\u0131n.","button_text":"\u0130leti\u015fim & rezervasyon","button_url":"\/iletisim","background_color":"#c4366e"}}]', NULL, 'published', '1', '0', NULL, '2026-04-01 06:52:21', '2026-04-02 17:04:51', NULL);
