INSERT INTO `pages` (`id`, `title`, `slug`, `meta_title`, `meta_description`, `og_title`, `og_description`, `og_image`, `blocks`, `schema_org`, `status`, `is_home`, `sort_order`, `parent_id`, `created_at`, `updated_at`, `deleted_at`) VALUES ('3', '{"tr":"Menü","en":"Menu"}', 'menumuz', '{"tr":null}', '{"tr":null}', '{"tr":null}', '{"tr":null}', NULL, '[{"type":"hero","data":{"heading":"QR Men\u00fc","subheading":"G\u00fcncel fiyatlar ve t\u00fcm kategoriler telefonunuzda. Masan\u0131zda QR ile de a\u00e7abilirsiniz.","button_label":"Men\u00fcy\u00fc a\u00e7","button_url":"http:\/\/specialroma.test\/menu\/special-roma\/4","button2_label":"PDF men\u00fc (bas\u0131l\u0131)","button2_url":"\/roma-menu.pdf","alignment":"center","min_height":"55vh","background_image":null,"style":null}},{"type":"text","data":{"alignment":"center","content":"<p>T\u00fcm \u00fcr\u00fcnlerimizi a\u015fa\u011f\u0131daki interaktif men\u00fcden inceleyebilirsiniz. PDF men\u00fcm\u00fcz\u00fc indirmek i\u00e7in ikinci butonu kullan\u0131n.<\/p>"}},{"type":"cta_banner","data":{"heading":"Hemen inceleyin","subheading":"Kategoriler aras\u0131nda gezinin; fiyatlar \u20ba olarak g\u00fcncellenir.","button_text":"QR men\u00fcy\u00fc a\u00e7","button_url":"http:\/\/specialroma.test\/menu\/special-roma\/4","background_color":"#0a3d62"}}]', NULL, 'published', '0', '5', NULL, '2026-04-01 07:44:49', '2026-04-01 07:54:40', NULL);
INSERT INTO `pages` (`id`, `title`, `slug`, `meta_title`, `meta_description`, `og_title`, `og_description`, `og_image`, `blocks`, `schema_org`, `status`, `is_home`, `sort_order`, `parent_id`, `created_at`, `updated_at`, `deleted_at`) VALUES ('4', '{"tr":"Hakkımızda","en":"About"}', 'hakkimizda', NULL, NULL, NULL, NULL, NULL, '[{"type":"hero","data":{"heading":"Hikayemiz","subheading":"1995\u2019ten beri ayn\u0131 \u00e7at\u0131 alt\u0131nda: lezzet, misafirperverlik ve Ege\u2019nin e\u015fsiz deniz esintisi.","alignment":"center","min_height":"45vh"}},{"type":"text","data":{"alignment":"center","content":"<div style=\"max-width:720px; margin:0 auto;\"><h2 style=\"text-align:center;\">Mordo\u011fan\u2019\u0131n Efsane Dura\u011f\u0131<\/h2><p style=\"font-size:1.1rem; line-height:1.8; text-align:center;\">Special Roma, \u0130zmir\u2019in sakl\u0131 cenneti Mordo\u011fan\u2019da, denizin hemen kenar\u0131nda, Cumhuriyet Meydan\u0131\u2019nda kap\u0131lar\u0131n\u0131 a\u00e7t\u0131. 1995 y\u0131l\u0131nda k\u00fc\u00e7\u00fck bir dondurma d\u00fckk\u00e2n\u0131 olarak ba\u015flayan yolculu\u011fumuz, bug\u00fcn tam donan\u0131ml\u0131 bir cafe, kahvalt\u0131 evi ve patisserie\u2019ye d\u00f6n\u00fc\u015ft\u00fc.<\/p><p style=\"font-size:1.05rem; line-height:1.8; text-align:center;\">Aslan & Musa karde\u015flerin kurdu\u011fu Special Roma, 30 y\u0131l\u0131 a\u015fk\u0131n s\u00fcredir aile s\u0131cakl\u0131\u011f\u0131yla misafirlerini a\u011f\u0131rl\u0131yor. Her sabah taze haz\u0131rlanan serpme kahvalt\u0131m\u0131z, el yap\u0131m\u0131 Roma dondurmalar\u0131 ve \u00f6zenle haz\u0131rlanan tatl\u0131lar\u0131m\u0131z ile Mordo\u011fan\u2019\u0131n vazge\u00e7ilmez bulu\u015fma noktas\u0131 olduk.<\/p><\/div>"}},{"type":"services_grid","data":{"heading":"De\u011ferlerimiz","columns":"3","services":[{"title":"Tazelik & Kalite","description":"Her g\u00fcn taze malzemeyle haz\u0131rlanan \u00fcr\u00fcnler, \u015feffaf mutfak k\u00fclt\u00fcr\u00fc.","icon":"\ud83c\udf3f","url":"#"},{"title":"Aile S\u0131cakl\u0131\u011f\u0131","description":"Aslan & Musa karde\u015flerin kurdu\u011fu aile i\u015fletmesi s\u0131cakl\u0131\u011f\u0131.","icon":"\ud83e\udd1d","url":"#"},{"title":"Ege Ruhu","description":"Mordo\u011fan\u2019\u0131n do\u011fas\u0131na ve yerel lezzetlerine derin sayg\u0131.","icon":"\ud83c\udf0a","url":"#"}]}},{"type":"text","data":{"alignment":"center","content":"<h2>Yolculu\u011fumuz<\/h2><p class=\"sr-story-lead\">K\u00fc\u00e7\u00fck bir dondurma d\u00fckk\u00e2n\u0131ndan Mordo\u011fan\u2019\u0131n simge mekan\u0131na\u2026<\/p><div class=\"sr-story-timeline\"><div class=\"sr-story-year\"><span class=\"sr-story-year__badge\">1995<\/span><p>Mordo\u011fan Cumhuriyet Meydan\u0131\u2019nda k\u00fc\u00e7\u00fck bir dondurma d\u00fckk\u00e2n\u0131 olarak kap\u0131lar\u0131m\u0131z\u0131 a\u00e7t\u0131k. Aslan & Musa karde\u015fler, el yap\u0131m\u0131 Roma dondurmalar\u0131yla ilk g\u00fcnden Ege\u2019nin en sevilen dura\u011f\u0131 olmay\u0131 ba\u015fard\u0131.<\/p><\/div><div class=\"sr-story-year\"><span class=\"sr-story-year__badge\">2005<\/span><p>Kahvalt\u0131 ve tatl\u0131 bar men\u00fcm\u00fcz\u00fc geni\u015flettik. Mordo\u011fan\u2019\u0131n efsane serpme kahvalt\u0131s\u0131 bu y\u0131llarda do\u011fdu.<\/p><\/div><div class=\"sr-story-year\"><span class=\"sr-story-year__badge\">2015<\/span><p>Mekan\u0131m\u0131z\u0131 tamamen yeniledik. Modern ve ferah bir tasar\u0131mla deniz manzaras\u0131n\u0131 sofraya ta\u015f\u0131d\u0131k.<\/p><\/div><div class=\"sr-story-year\"><span class=\"sr-story-year__badge\">Bug\u00fcn<\/span><p>30 y\u0131l\u0131 a\u015fk\u0131n tecr\u00fcbe, ayn\u0131 tutku. Onlarca dondurma aromas\u0131, geni\u015f bir men\u00fc ve samimi bir hizmet anlay\u0131\u015f\u0131yla buraday\u0131z.<\/p><\/div><\/div>"}},{"type":"text","data":{"alignment":"center","content":"<div style=\"max-width:720px; margin:0 auto;\"><h2 style=\"text-align:center;\">Ne Sunuyoruz?<\/h2><div style=\"display:grid; grid-template-columns:repeat(auto-fit,minmax(200px,1fr)); gap:1.5rem; margin-top:2rem;\"><div style=\"text-align:center; padding:1.5rem; border-radius:1.25rem; background:#fff; border:1px solid rgb(196 54 110 \/ 0.06);\"><p style=\"font-size:2rem; margin:0 0 0.5rem;\">\ud83c\udf68<\/p><p style=\"font-weight:600; margin:0 0 0.35rem;\">Roma Dondurmalar\u0131<\/p><p style=\"font-size:0.9rem; color:var(--color-muted); margin:0;\">Klasik ve special aromalar, her g\u00fcn taze. 30+ \u00e7e\u015fit.<\/p><\/div><div style=\"text-align:center; padding:1.5rem; border-radius:1.25rem; background:#fff; border:1px solid rgb(196 54 110 \/ 0.06);\"><p style=\"font-size:2rem; margin:0 0 0.5rem;\">\u2600\ufe0f<\/p><p style=\"font-weight:600; margin:0 0 0.35rem;\">Serpme Kahvalt\u0131<\/p><p style=\"font-size:0.9rem; color:var(--color-muted); margin:0;\">Zengin peynir & zeytin se\u00e7kisi, deniz kenar\u0131nda huzur.<\/p><\/div><div style=\"text-align:center; padding:1.5rem; border-radius:1.25rem; background:#fff; border:1px solid rgb(196 54 110 \/ 0.06);\"><p style=\"font-size:2rem; margin:0 0 0.5rem;\">\ud83c\udf70<\/p><p style=\"font-weight:600; margin:0 0 0.35rem;\">Patisserie & Tatl\u0131lar<\/p><p style=\"font-size:0.9rem; color:var(--color-muted); margin:0;\">Waffle, dilim pasta, \u015ferbetli tatl\u0131lar ve milkshake.<\/p><\/div><div style=\"text-align:center; padding:1.5rem; border-radius:1.25rem; background:#fff; border:1px solid rgb(196 54 110 \/ 0.06);\"><p style=\"font-size:2rem; margin:0 0 0.5rem;\">\ud83c\udf54<\/p><p style=\"font-weight:600; margin:0 0 0.35rem;\">Ana Yemekler<\/p><p style=\"font-size:0.9rem; color:var(--color-muted); margin:0;\">Burger, makarna, salata ve aperatifler.<\/p><\/div><\/div><\/div>"}},{"type":"testimonials","data":{"heading":"Misafirlerimiz ne diyor?","eyebrow":"Yorumlar","items":[{"quote":"Dondurmalar harika, manzara e\u015fsiz. Her yaz mutlaka u\u011fruyoruz.","author_name":"Elif S.","author_title":"\u0130zmir"},{"quote":"Serpme kahvalt\u0131 ger\u00e7ekten doyurucu ve taze. Personel \u00e7ok ilgili.","author_name":"Can T.","author_title":"Mordo\u011fan"},{"quote":"Roma waffle ve special dondurma se\u00e7imi ile \u00e7ocuklar bay\u0131ld\u0131.","author_name":"P\u0131nar K.","author_title":"Ala\u00e7at\u0131"}]}},{"type":"cta_banner","data":{"heading":"Bizi ziyaret edin","subheading":"Mordo\u011fan sahilinde, Cumhuriyet Meydan\u0131 No:13. Her g\u00fcn 08:00 \u2013 24:00.","button_text":"\u0130leti\u015fim","button_url":"\/iletisim","background_color":"#c4366e"}}]', NULL, 'published', '0', '10', NULL, '2026-04-01 07:44:49', '2026-04-01 09:32:04', NULL);
